import{_ as t,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as s,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Safety/user-rate-limits.md","filePath":"ur/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"ur/Safety/user-rate-limits.md"};function o(p,e,n,u,c,m){return s(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits یہ کنٹرول کرتے ہیں کہ regular users یا visitors homepage سے کتنی بار files upload کر سکتے ہیں۔ اس سے public upload pages کے abuse کو کم کرنے میں مدد ملتی ہے۔</p><p>یہ feature صرف homepage uploads کو متاثر کرتا ہے۔ Admin uploads اور API Tokens کے ذریعے کیے گئے uploads پر user rate limits لاگو نہیں ہوتیں۔</p><h2 id="کہاں-configure-کریں" tabindex="-1">کہاں Configure کریں <a class="header-anchor" href="#کہاں-configure-کریں" aria-label="Permalink to &quot;کہاں Configure کریں&quot;">​</a></h2><p>admin panel کھولیں، پھر جائیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+t+'" alt="User rate limit settings" loading="lazy"></p><h2 id="rate-limits-enable-کرنا" tabindex="-1">Rate Limits Enable کرنا <a class="header-anchor" href="#rate-limits-enable-کرنا" aria-label="Permalink to &quot;Rate Limits Enable کرنا&quot;">​</a></h2><p><code>Enable Rate Limits</code> on ہونے کے بعد ImgBed uploader IP address کے حساب سے recent uploads track کرتا ہے۔</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>کتنے پیچھے تک upload records count ہوں گے۔</td></tr><tr><td>Max file count</td><td>20</td><td>detection window میں allowed maximum files۔</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>ایک file کا maximum size۔</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>detection window میں maximum total upload size۔</td></tr></tbody></table><p>مثلاً 1.5 hour window، 20 files، ہر file 20 MB، اور total 200 MB کے ساتھ، same IP سے uploads تب block ہوں گے جب کوئی بھی configured limit exceed ہو جائے۔</p><h2 id="file-types-exclude-کرنا" tabindex="-1">File Types Exclude کرنا <a class="header-anchor" href="#file-types-exclude-کرنا" aria-label="Permalink to &quot;File Types Exclude کرنا&quot;">​</a></h2><p><code>Excluded upload file types</code> regular users یا visitors کو selected file categories upload کرنے سے روکتا ہے۔</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif، اور اسی طرح کی image files</td></tr><tr><td>Videos</td><td>mp4, webm, mov، اور اسی طرح کی video files</td></tr><tr><td>Audio</td><td>mp3, flac, wav، اور اسی طرح کی audio files</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx، اور اسی طرح کی document files</td></tr><tr><td>Other</td><td>اوپر والی categories سے باہر files، جیسے zip, rar, exe, apk</td></tr></tbody></table><p>default طور پر کوئی type selected نہیں ہوتا، یعنی وہ allowed ہے۔</p><p>کسی type پر کلک کرنے سے وہ highlight ہوتا ہے، یعنی وہ type blocked ہے۔</p><p>اگر <code>Other</code> selected ہو، تو zip یا rar files upload کرنے والے visitors block ہوں گے اور انہیں بتایا جائے گا کہ یہ file type supported نہیں۔</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>limit trigger ہونے پر users کو matching message دکھتا ہے:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>file بہت بڑی ہے اور upload سے پہلے compress کرنی چاہیے۔</td></tr><tr><td>File type blocked</td><td>یہ file type supported نہیں۔ اسے remove کر کے دوبارہ کوشش کریں۔</td></tr><tr><td>Uploads too frequent</td><td>recent uploads بہت frequent ہیں، retry time کے ساتھ message دکھتا ہے۔</td></tr><tr><td>Total size too high</td><td>recent total upload size بہت زیادہ ہے، retry time کے ساتھ message دکھتا ہے۔</td></tr></tbody></table><h2 id="کب-enable-کریں" tabindex="-1">کب Enable کریں <a class="header-anchor" href="#کب-enable-کریں" aria-label="Permalink to &quot;کب Enable کریں&quot;">​</a></h2><p>اگر آپ کا upload homepage public accessible ہے تو user rate limits enable کریں۔</p><p>عام وجوہات:</p><ul><li>آپ scripted bulk uploads کے بارے میں فکر مند ہیں۔</li><li>آپ visitor uploads کا size limit کرنا چاہتے ہیں۔</li><li>آپ چاہتے ہیں regular users صرف images upload کریں، archives یا installers نہیں۔</li><li>آپ public upload available رکھنا چاہتے ہیں مگر resource usage control کرنا چاہتے ہیں۔</li></ul><p>اگر site صرف آپ کے لیے ہے، یا صرف administrators upload کرتے ہیں، تو اسے disabled چھوڑ سکتے ہیں۔</p>',28)])])}const f=i(r,[["render",o]]);export{b as __pageData,f as default};
